import { ref } from 'vue'
import { useStore } from 'vuex'
import { useRouter } from 'vue-router'
import { auth } from '@/api/auth'
import { showToast } from '@/components/ToastMessage'
import request from '@/utils/request'

export function useDeleteAccount() {
  const store = useStore()
  const router = useRouter()

  const showDeleteConfirm = ref(false)
  const deletePassword = ref('')
  const loading = ref(false)

  // 清理所有状态
  const clearAllState = () => {
    // 1. 先清除请求头
    delete request.defaults.headers.common['Authorization']

    // 2. 清除本地存储
    localStorage.clear()

    // 3. 清除 store 状态
    store.commit('SET_LOGGED_IN', false)
    store.commit('SET_TOKEN', null)
    store.commit('SET_REFRESH_TOKEN', null)
    store.commit('CLEAR_USER_INFO')
    store.commit('CLEAR_BASIC_INFO')
  }

  // 处理注销账户
  const handleDeleteAccount = async () => {
    try {
      if (!deletePassword.value) {
        showToast('请输入密码确认', 'warning')
        return
      }

      loading.value = true

      let isDeleted = false
      try {
        const response = await auth.deleteAccount({
          password: deletePassword.value
        })
        // 如果请求成功，标记为已删除
        if (response.data?.code === 200) {
          isDeleted = true
        }
      } catch (error) {
        // 如果是 401 错误，也认为账号已被删除
        if (error.response?.status === 401) {
          isDeleted = true
        } else {
          throw error
        }
      }

      // 只有在确认账号已删除时才执行清理流程
      if (isDeleted) {
        clearAllState()
        showToast('账户已注销', 'success')
        showDeleteConfirm.value = false // 只在成功时关闭确认框

        // 延迟一下再跳转，确保状态都清理完毕
        setTimeout(() => {
          router.replace('/login')
        }, 100)
      }

    } catch (error) {
      const errorMessage = error.response?.data?.message || '注销账户失败，请重试'
      showToast(errorMessage, 'error')
      // 密码错误时清空密码输入
      if (error.response?.data?.message?.includes('密码错误')) {
        deletePassword.value = ''
      }
    } finally {
      loading.value = false
    }
  }

  return {
    showDeleteConfirm,
    deletePassword,
    loading,
    handleDeleteAccount
  }
}
